import React, { useState } from 'react';
import { useApp } from '../../App';
import { Sidebar } from '../../components/Sidebar';
import LiveMap from '../../components/LiveMap';

// Firebase Modules
import { db } from '../../utils/firebase';
import { doc, getDoc, collection, getDocs } from 'firebase/firestore';

export default function CleanerPortal() {
  const { complaints, updateComplaint } = useApp();

  // Authentication State Drivers
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [parentVendorId, setParentVendorId] = useState('');
  const [cleanerLoginId, setCleanerLoginId] = useState('');
  const [cleanerPassword, setCleanerPassword] = useState('');
  const [activeCleanerData, setActiveCleanerData] = useState(null);

  // Workflow Action States
  const [selected, setSelected] = useState(null);
  const [proofUrl, setProofUrl] = useState('');
  const [isAuthLoading, setIsAuthLoading] = useState(false);

  // Active Tasks Filters (Dynamic tracking string mapping)
  const activeTasks = complaints.filter(c => 
    c.assignedTo?.toLowerCase().trim() === activeCleanerData?.name?.toLowerCase().trim() && 
    ['ASSIGNED_TO_CLEANER', 'CLEANED_BY_FORCE'].includes(c.status)
  );

  // ── FIX: RE-ARCHITECTED STANDALONE REST DISPATCH AUTH ──
  const handleCleanerLoginAuth = async (e) => {
    e.preventDefault();
    
    // Normalizing spaces to avoid "Parent Vendor ID not found" string mismatch
    const cleanVendorId = parentVendorId.trim().toLowerCase().replace(/\s+/g, ' '); 
    const cleanLoginId = cleanerLoginId.trim();

    if (!cleanVendorId || !cleanLoginId || !cleanerPassword) {
      return alert("Please fill all configuration fields.");
    }

    setIsAuthLoading(true);

    try {
      // Direct doc verification bypass mapping
      const vendorRef = doc(db, "vendors", cleanVendorId);
      const vendorSnap = await getDoc(vendorRef);

      // WebChannel error fix fallback: If direct doc fetch fails due to routing names, fallback query check
      if (!vendorSnap.exists()) {
        setIsAuthLoading(false);
        return alert(`Configuration Ref Mismatch: Vendor station matching "${cleanVendorId}" does not exist inside Firestore root database schemas.`);
      }

      // Safe HTTP call via getDocs instead of persistent stream channel loops (Fixes WebChannel 400 error)
      const cleanerSubCollectionRef = collection(db, "vendors", cleanVendorId, "cleaners");
      const subSnap = await getDocs(cleanerSubCollectionRef);
      
      let authenticatedStaff = null;
      
      subSnap.forEach((docItem) => {
        const data = docItem.data();
        if (
          String(data.phone).trim() === cleanLoginId && 
          String(data.password) === String(cleanerPassword).trim()
        ) {
          authenticatedStaff = data;
        }
      });

      if (authenticatedStaff) {
        setActiveCleanerData(authenticatedStaff);
        setIsAuthenticated(true);
      } else {
        alert("Authentication Failed: Invalid Staff Phone or Account Password matching this registry profile.");
      }

    } catch (err) {
      console.error("Authentication handshake trace:", err);
      alert("Database Network Stream Blocked: Check if your browser's Tracking Prevention or Shield is blocking Firebase storage tokens.");
    } finally {
      setIsAuthLoading(false);
    }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setActiveCleanerData(null);
    setCleanerLoginId('');
    setCleanerPassword('');
    setSelected(null);
  };

  const handleSendProofToVendor = async (taskId) => {
    if (!proofUrl.trim()) {
      return alert("Please paste the valid clean site proof media URL before notification triggers.");
    }

    try {
      await updateComplaint(taskId, {
        status: 'CLEANED_BY_FORCE',
        cleanerStatus: 'DONE',
        cleanerPhoto: proofUrl.trim()
      });

      alert("Success! Verification image pipeline sent to Vendor monitoring workspace.");
      setProofUrl('');
      setSelected(null);
    } catch (err) {
      alert("Failed updating remote record nodes.");
    }
  };

  /* ── VIEWPORT 1: STYLED LOCKDOWN GATEWAY INTERFACE ── */
  if (!isAuthenticated) {
    return (
      <div style={{ display: 'flex', minHeight: '100vh', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', background: '#0F172A', fontFamily: 'system-ui, sans-serif' }}>
        <div style={{ background: '#fff', padding: '34px 28px', borderRadius: 16, width: 340, boxShadow: '0 12px 40px rgba(0,0,0,0.3)' }}>
          
          <div style={{ textAlign: 'center', marginBottom: 22 }}>
            <div style={{ fontSize: 26, marginBottom: 4 }}>🧹</div>
            <div style={{ fontSize: 18, fontWeight: 800, color: '#1E293B' }}>Field Force Login</div>
            <div style={{ fontSize: 11, color: '#64748B', fontWeight: 600, textTransform: 'uppercase', letterSpacing: 0.5, marginTop: 4 }}>GRWMS Cleaner Node</div>
          </div>

          <form onSubmit={handleCleanerLoginAuth}>
            
            <div style={{ marginBottom: 14 }}>
              <label style={{ display: 'block', fontSize: 10, fontWeight: 700, color: '#475569', marginBottom: 5 }}>CLEANER LOGIN ID (PHONE / USERNAME)</label>
              <input type="text" value={cleanerLoginId} onChange={e => setCleanerLoginId(e.target.value)} placeholder="e.g. vikash" style={{ width: '100%', padding: '10px 12px', borderRadius: 8, border: '1px solid #CBD5E1', boxSizing: 'border-box', fontSize: 13 }} required />
            </div>

            <div style={{ marginBottom: 20 }}>
              <label style={{ display: 'block', fontSize: 10, fontWeight: 700, color: '#475569', marginBottom: 5 }}>APP ACCESS PASSWORD</label>
              <input type="password" value={cleanerPassword} onChange={e => setCleanerPassword(e.target.value)} placeholder="••••••••" style={{ width: '100%', padding: '10px 12px', borderRadius: 8, border: '1px solid #CBD5E1', boxSizing: 'border-box', fontSize: 13 }} required />
            </div>

            <button type="submit" disabled={isAuthLoading} style={{ width: '100%', padding: 12, background: isAuthLoading ? '#94A3B8' : '#10B981', color: '#fff', border: 'none', borderRadius: 8, fontWeight: 700, fontSize: 13, cursor: isAuthLoading ? 'not-allowed' : 'pointer' }}>
              {isAuthLoading ? "Validating Parameters..." : "Sign In & Sync Work Orders"}
            </button>
          </form>

        </div>
      </div>
    );
  }

  /* ── VIEWPORT 2: PRODUCTION MAIN WORKSPACE OPERATION ── */
  return (
    <div style={{ display: 'flex', height: '100vh', background: '#F7F9FC', overflow: 'hidden', fontFamily: 'system-ui, sans-serif' }}>
      
      <Sidebar 
        title="Field Force Ledger" 
        subtitle={`Operator: ${activeCleanerData?.name}`} 
        navItems={[{ key: 'JOBS', label: 'Assigned Sweeps', icon: '🧹', count: activeTasks.length }]} 
        activeTab="JOBS" 
        onTabChange={() => {}} 
      />

      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        
        {/* Dynamic Context Dashboard Ribbon Bar */}
        <div style={{ background: '#fff', borderBottom: '1px solid #E2E8F0', padding: '12px 20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <span style={{ fontSize: 12, color: '#64748B' }}>Station Node Instance: </span>
            <strong style={{ fontSize: 12, color: '#0F172A', textTransform: 'uppercase' }}>{parentVendorId}</strong>
          </div>
          <button onClick={handleLogout} style={{ background: '#F1F5F9', border: 'none', padding: '6px 14px', borderRadius: 6, cursor: 'pointer', fontSize: 11, fontWeight: 700, color: '#475569' }}>
            Logout Session
          </button>
        </div>

        {/* Operational Flow Window split */}
        <div style={{ flex: 1, display: 'flex', padding: 20, gap: 16, overflow: 'hidden' }}>
          
          {/* LIST BOX GRID CONFIG */}
          <div style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 10 }}>
            <h3 style={{ fontSize: 14, color: '#0F172A', margin: '0 0 2px 0', fontWeight: 800 }}>📋 Operational Duty Worklist</h3>
            
            {activeTasks.length === 0 ? (
              <div style={{ background: '#fff', padding: 30, borderRadius: 12, border: '1px solid #DDE3E9', textAlign: 'center', color: '#7A8FA6', fontSize: 13 }}>
                No active duty jobs matching your crew deployment name right now.
              </div>
            ) : (
              activeTasks.map(t => {
                const isDispatched = t.status === 'CLEANED_BY_FORCE';
                return (
                  <div 
                    key={t.id} 
                    onClick={() => setSelected(t)} 
                    style={{ 
                      background: isDispatched ? '#FFFBEB' : '#fff', 
                      padding: 14, 
                      borderRadius: 12, 
                      border: `1px solid ${selected?.id === t.id ? '#1565C0' : isDispatched ? '#FDE68A' : '#DDE3E9'}`, 
                      cursor: 'pointer',
                      boxShadow: '0 2px 4px rgba(0,0,0,0.01)'
                    }}
                  >
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <div style={{ fontWeight: 700, fontSize: 13, color: '#1E293B' }}>📍 {t.area || 'Platform Site Area'}</div>
                      {isDispatched && (
                        <span style={{ background: '#D97706', color: '#fff', fontSize: 9, padding: '2px 6px', borderRadius: 4, fontWeight: 700 }}>Awaiting Audit</span>
                      )}
                    </div>
                    <div style={{ fontSize: 11, color: '#64748B', marginTop: 4 }}>
                      Ref Code ID: <strong>{t.customTicketId || t.id?.substring(0, 5)}</strong> | Hazard: {t.title || t.gtype}
                    </div>
                  </div>
                );
              })
            )}
          </div>

          {/* TELEMETRY DETAILS & ACTION DATA INTAKE VIEW */}
          <div style={{ flex: 1, background: '#fff', borderRadius: 14, border: '1px solid #DDE3E9', padding: 18, display: 'flex', flexDirection: 'column', gap: 14, overflowY: 'auto' }}>
            {selected ? (
              <>
                <div>
                  <h4 style={{ margin: '0 0 2px 0', fontSize: 14, color: '#0F172A' }}>Deployment Target Location</h4>
                  <span style={{ fontSize: 11, color: '#64748B' }}>Target spatial telemetry matrix parameters</span>
                </div>

                <LiveMap singlePin={true} singleCoords={{ lat: selected.lat, lng: selected.lng }} height="140px" />
                
                {selected.lat && selected.lng && (
                  <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: '#F8FAFC', padding: 8, borderRadius: 6, border: '1px solid #E2E8F0' }}>
                    <span style={{ fontSize: 10, fontFamily: 'monospace', color: '#334155' }}>GPS: {selected.lat}, {selected.lng}</span>
                    <a href={`https://www.google.com/maps/search/?api=1&query=${selected.lat},${selected.lng}`} target="_blank" rel="noreferrer" style={{ background: '#1E40AF', color: '#fff', padding: '4px 8px', borderRadius: 4, fontSize: 10, fontWeight: 700, textDecoration: 'none' }}>Navigation Link Map</a>
                  </div>
                )}

                {/* Left-Right Asset Verification Data Display */}
                <div>
                  <span style={{ fontSize: 11, fontWeight: 700, color: '#EF4444', display: 'block', marginBottom: 6 }}>⚠️ CITIZEN INITIAL DISPATCH TRACE (BEFORE):</span>
                  {(selected.imageUrl || selected.image) ? (
                    <img src={selected.imageUrl || selected.image} alt="Trace evidence" style={{ width: '100%', height: 120, objectFit: 'cover', borderRadius: 8, border: '1px solid #FCA5A5' }} />
                  ) : (
                    <div style={{ background: '#F8FAFC', padding: 10, borderRadius: 6, fontSize: 11, color: '#64748B', textAlign: 'center', fontStyle: 'italic' }}>No baseline image attached by reporter.</div>
                  )}
                </div>

                {/* Dynamic Bottom Processing Controls Container */}
                <div style={{ marginTop: 'auto', borderTop: '1px solid #E2E8F0', paddingTop: 12 }}>
                  {selected.status === 'ASSIGNED_TO_CLEANER' ? (
                    <div style={{ background: '#F8FAFC', padding: 12, borderRadius: 10, border: '1px solid #E2E8F0' }}>
                      <label style={{ fontSize: 11, fontWeight: 700, color: '#1E293B', display: 'block', marginBottom: 6 }}>📸 PROOF FEEDBACK: SUBMIT AFTER-CLEAN PHOTO URL</label>
                      <input type="text" placeholder="Paste structural image URL..." value={proofUrl} onChange={e => setProofUrl(e.target.value)} style={{ width: '100%', padding: '10px', fontSize: 12, borderRadius: 6, border: '1px solid #CBD5E1', boxSizing: 'border-box', marginBottom: 10 }} />
                      <button onClick={() => handleSendProofToVendor(selected.id)} style={{ width: '100%', background: '#059669', color: '#fff', padding: 11, border: 'none', borderRadius: 6, fontWeight: 700, fontSize: 12, cursor: 'pointer' }}>Dispatch Job to Vendor Audit Grid</button>
                    </div>
                  ) : (
                    <div style={{ background: '#FEF3C7', border: '1px solid #FCD34D', borderRadius: 10, padding: 12, textAlign: 'center' }}>
                      <div style={{ fontSize: 12, fontWeight: 700, color: '#B45309', marginBottom: 3 }}>⏳ Awaiting Dual Asset Audit Verification</div>
                      <div style={{ fontSize: 11, color: '#4B5563' }}>Task submitted successfully! Waiting for Vendor Head to inspect both pictures and mark as officially COMPLETED.</div>
                    </div>
                  )}
                </div>
              </>
            ) : (
              <div style={{ margin: 'auto', color: '#94A3B8', fontSize: 12, textAlign: 'center' }}>Select a ticket from the checklist matrix view to map route telemetry.</div>
            )}
          </div>

        </div>
      </div>
    </div>
  );
}
